+    {
+      const APInt *C;
+      Value *X;
+      if (match(Src, m_LShr(m_APInt(C), m_Value(X))) && C->isPowerOf2()) {
+        // trunc (C >> X) to i1 --> X == log2(C), where C is pow2
+        Constant *Log2C = ConstantInt::get(SrcTy, C->logBase2());
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+      }
+      if (match(Src, m_LShr(m_APInt(C), m_Value(X))) && (*C + 1).isPowerOf2()) {
+        // trunc (C >> X) to i1 --> X < log2(C + 1), where C + 1 is pow2
+        Constant *Log2C = ConstantInt::get(SrcTy, (*C + 1).logBase2());
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, Log2C);
+      }
+    }
+
+    {
+      const APInt *C;
+      Value *X;
+      if (match(Src, m_AShr(m_APInt(C), m_Value(X))) && C->isPowerOf2()) {
